# ✅ BEST PRACTICE: Cache model in memory, lazy-load once
from transformers import pipeline
import functools

@functools.lru_cache(maxsize=1)
def get_cricket_analyzer():
    """Singleton pattern: model loaded once, reused across requests"""
    return pipeline('sentiment-analysis', model='distilbert-base-uncased')

def score_cricket_commentary(text):
    analyzer = get_cricket_analyzer()
    return analyzer(text)

result1 = score_cricket_commentary("That was a magnificent six!")  # ~3s first call
result2 = score_cricket_commentary("Brilliant fielding!")  # ~50ms cached call

# ✅ PRODUCTION BEST PRACTICE: Version-pinned model from HF Hub with explicit device
from transformers import AutoTokenizer, AutoModelForSequenceClassification
import torch

class CricketSentimentBatter:
    """Stateful inference server with versioning"""
    def __init__(self, model_id="distilbert-base-uncased", revision="main"):
        self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
        self.tokenizer = AutoTokenizer.from_pretrained(model_id, revision=revision)
        self.model = AutoModelForSequenceClassification.from_pretrained(
            model_id, revision=revision
        ).to(self.device).eval()

    def predict(self, cricket_text):
        inputs = self.tokenizer(cricket_text, return_tensors="pt").to(self.device)
        with torch.no_grad():
            logits = self.model(**inputs).logits
        return {"label": logits.argmax().item(), "confidence": logits.softmax(dim=1).max().item()}

# Usage
batter = CricketSentimentBatter(model_id="distilbert-base-uncased", revision="v1.0")
print(batter.predict("Stunning catch by the fielder!"))
